      "content": "'use strict';\n\n/*\n * Copyright (c) 2016 TopCoder, Inc.\n */\n\n/**\n * Service for SRM problem APIs.\n */\nconst fs = require('fs');\nconst path = require('path');\nconst Joi = require('joi');\nconst logger = require('../../../common/logger');\n\nlet cachedProblems;\n\nconst MAX_LIMIT = 50;\n\n/**\n * Normalize tags filter into a lowercase array.\n * @param {string|Array<string>} rawTags\n * @returns {Array<string>}\n */\nfunction normalizeTags(rawTags) {\n  if (!rawTags && rawTags !== '') {\n    return [];\n  }\n  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');\n  return list\n    .map((tag) => String(tag || '').trim().toLowerCase())\n    .filter((tag) => tag);\n}\n\n/**\n * Check whether the problem contains at least one of the requested tags.\n * @param {Object} problem\n * @param {Array<string>} tags\n * @returns {boolean}\n */\nfunction problemHasTags(problem, tags) {\n  if (!tags || tags.length === 0) return true;\n  if (!problem.tags || !Array.isArray(problem.tags)) return false;\n  const problemTags = problem.tags.map((t) => t.toLowerCase());\n  return tags.some((tag) => problemTags.includes(tag));\n}\n\n/**\n * Load problems from JSON file, cache them.\n * @returns {Array<Object>}\n */\nfunction loadProblems() {\n  if (cachedProblems) return cachedProblems;\n  const filePath = path.resolve(__dirname, '../../data/problems.json');\n  const raw = fs.readFileSync(filePath, 'utf8');\n  cachedProblems = JSON.parse(raw);\n  return cachedProblems;\n}\n\n/**\n * Aggregate component statistics for a problem.\n * @param {Object} problem\n * @returns {Object} componentStats\n */\nfunction aggregateComponentStats(problem) {\n  const languages = {};\n  const statusCounts = {};\n  let maxPoints = 0;\n\n  if (problem.components && Array.isArray(problem.components)) {\n    for (const comp of problem.components) {\n      // Count languages\n      if (comp.language) {\n        languages[comp.language] = (languages[comp.language] || 0) + 1;\n      }\n      // Count status\n      if (comp.status) {\n        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;\n      }\n      // Track max points\n      if (typeof comp.points === 'number' && comp.points > maxPoints) {\n        maxPoints = comp.points;\n      }\n    }\n  }\n\n  return {\n    languages,\n    statusCounts,\n    maxPoints\n  };\n}\n\n/**\n * List problems with optional filtering and pagination.\n * @param {Object} query\n * @returns {Promise<Object>} payload\n */\nfunction* listProblems(query) {\n  const problems = loadProblems();\n\n  // Normalize tags filter"}], "localized": true}
